#!/usr/bin/env bash
# cyberware plan · skill=fs perk=find_large · value-free; the caller exports SNIP/RECORD_STORE/vars
set -uo pipefail
: "${SNIP:?SNIP must point at the perk snippet dir}" "${RECORD_STORE:?}"
mkdir -p "$RECORD_STORE"

step1() {   # fs_find_large
  echo "[step 1] fs_find_large"
  bash "$SNIP/fs_find_large.sh"
  test -f "${RECORD_STORE}/large_files.txt" || { echo "CONTRACT FAIL step 1: missing ${RECORD_STORE}/large_files.txt" >&2; exit 3; }
}

case "${1:-}" in
  --list) printf "1\tfs_find_large\n" ;;
  --step) shift; "step${1:?step number}" ;;
  --all) step1 ;;
  *) echo "usage: $0 --list | --step <N> | --all" >&2; exit 2 ;;
esac
